{"content": "@import "tailwindcss";

/* Mystic Purple Theme — Deep, ethereal, cosmic purple */
:root {
  --color-mystic-50: #f0e6ff;
  --color-mystic-100: #d9b3ff;
  --color-mystic-200: #c080ff;
  --color-mystic-300: #a64dff;
  --color-mystic-400: #8e1aff;
  --color-mystic-500: #7b2d8e;
  --color-mystic-600: #6a1b7a;
  --color-mystic-700: #590f66;
  --color-mystic-800: #480852;
  --color-mystic-900: #37033e;
  --color-mystic-950: #1a001f;
}

@theme {
  --color-mystic-50: #f0e6ff;
  --color-mystic-100: #d9b3ff;
  --color-mystic-200: #c080ff;
  --color-mystic-300: #a64dff;
  --color-mystic-400: #8e1aff;
  --color-mystic-500: #7b2d8e;
  --color-mystic-600: #6a1b7a;
  --color-mystic-700: #590f66;
  --color-mystic-800: #480852;
  --color-mystic-900: #37033e;
  --color-mystic-950: #1a001f;
}

body {
  margin: 0;
  background: linear-gradient(135deg, #0a0012 0%, #1a0025 25%, #37033e 50%, #1a0025 75%, #0a0012 100%);
  color: #e2d9f0;
  font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
  min-height: 100vh;
}

/* Glass morphism cards */
.glass-card {
  background: rgba(30, 15, 60, 0.6);
  backdrop-filter: blur(12px);
  border: 1px solid rgba(142, 26, 255, 0.2);
  border-radius: 16px;
  transition: all 0.3s ease;
}

.glass-card:hover {
  border-color: rgba(142, 26, 255, 0.5);
  box-shadow: 0 0 20px rgba(142, 26, 255, 0.15);
  transform: translateY(-2px);
}

/* Gradient text */
.gradient-text {
  background: linear-gradient(135deg, #d9b3ff, #8e1aff, #c080ff);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Glow effects */
.glow-purple {
  box-shadow: 0 0 30px rgba(142, 26, 255, 0.3), 0 0 60px rgba(142, 26, 255, 0.1);
}

/* Scrollbar */
::-webkit-scrollbar { width: 8px; }
::-webkit-scrollbar-track { background: #0f0a1a; }
::-webkit-scrollbar-thumb { background: #6a1b7a; border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: #8e1aff; }

/* Smooth scroll */
html { scroll-behavior: smooth; }

/* Dash preview mockup */
.dash-frame {
  background: linear-gradient(145deg, #1a1035, #23104a);
  border: 1px solid rgba(142, 26, 255, 0.3);
  border-radius: 12px;
  overflow: hidden;
  height: 112px !important;
}

/* Timeline line */
.timeline-line {
  background: linear-gradient(to bottom, rgba(142,26,255,0.6), rgba(142,26,255,0.1), transparent);
}

.timeline-dot {
  box-shadow: 0 0 12px rgba(142,26,255,0.5);
}

/* Hero gradient orbs */
@keyframes orbFloat {
  0%, 100% { transform: translate(0, 0) scale(1); opacity: 0.3; }
  33% { transform: translate(30px, -20px) scale(1.1); opacity: 0.5; }
  66% { transform: translate(-20px, 10px) scale(0.9); opacity: 0.4; }
}

.orb-1 { animation: orbFloat 8s ease-in-out infinite; }
.orb-2 { animation: orbFloat 10s ease-in-out infinite reverse; }
.orb-3 { animation: orbFloat 12s ease-in-out infinite; animation-delay: -4s; }

/* Skill bar animation */
@keyframes skillFill {
  from { width: 0 !important; }
  to { width: var(--skill-width); }
}

.skill-bar-inner {
  animation: skillFill 1.5s ease-out forwards;
}
